var CORS = {
  "Access-Control-Allow-Origin": "https://ricardoruiz.co",
  "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization",
  "Access-Control-Allow-Credentials": "true"
};
function cors(body, status = 200, extra = {}) {
  return new Response(body, { status, headers: { "Content-Type": "application/json", ...CORS, ...extra } });
}
function ok(data) { return cors(JSON.stringify({ ok: true, ...data })); }
function err(msg, status = 400) { return cors(JSON.stringify({ ok: false, error: msg }), status); }

async function hashPassword(password, salt) {
  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey("raw", enc.encode(password), { name: "PBKDF2" }, false, ["deriveBits"]);
  const bits = await crypto.subtle.deriveBits({ name: "PBKDF2", salt: enc.encode(salt), iterations: 1e5, hash: "SHA-256" }, key, 256);
  return btoa(String.fromCharCode(...new Uint8Array(bits)));
}
function randomToken(bytes = 32) {
  const arr = new Uint8Array(bytes);
  crypto.getRandomValues(arr);
  return Array.from(arr).map(b => b.toString(16).padStart(2, "0")).join("");
}
function randomCode() {
  const arr = new Uint8Array(3);
  crypto.getRandomValues(arr);
  return String((arr[0] << 16 | arr[1] << 8 | arr[2]) % 1e6).padStart(6, "0");
}
function getToken(request) {
  const auth = request.headers.get("Authorization") || "";
  if (auth.startsWith("Bearer ")) return auth.slice(7);
  return null;
}

