// Ray casting sobre un anillo cerrado (array de [x,y]).
function _pir(pt, ring) {
  const x = pt[0], y = pt[1];
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    if (((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / ((yj - yi) || 1e-15) + xi)) {
      inside = !inside;
    }
  }
  return inside;
}

// PiP sobre {k:'p', c:rings} (Polygon) o {k:'m', c:[[rings],...]} (MultiPolygon).
function _pig(pt, g) {
  if (g.k === 'p') {
    const rings = g.c;
    if (!rings.length || !_pir(pt, rings[0])) return false;
    for (let i = 1; i < rings.length; i++) if (_pir(pt, rings[i])) return false;
    return true;
  }
  for (const poly of g.c) {
    if (!poly.length) continue;
    if (!_pir(pt, poly[0])) continue;
    let inHole = false;
    for (let i = 1; i < poly.length; i++) {
      if (_pir(pt, poly[i])) { inHole = true; break; }
    }
    if (!inHole) return true;
  }
  return false;
}

// Helper: encuentra primer feature de una capa que contenga el punto.
function _findInLayer(pt, layer) {
  for (const e of layer) {
    const bb = e.bb;
    if (pt[0] < bb[0] || pt[0] > bb[2] || pt[1] < bb[1] || pt[1] > bb[3]) continue;
    if (_pig(pt, e.g)) return e;
  }
  return null;
}

// Devuelve {city, scope, label, codigo, sub?, sub_codigo?} para el lat/lon dado,
// o {} si no está en ninguna de las ciudades soportadas.
function cityLookup(lat, lon) {
  if (lat == null || lon == null) return {};
  const pt = [lon, lat];
  // Bogotá
  if (lon >= BOG_BBOX[0] && lon <= BOG_BBOX[2] && lat >= BOG_BBOX[1] && lat <= BOG_BBOX[3]) {
    const upl = _findInLayer(pt, BOG_UPL);
    const loc = _findInLayer(pt, BOG_LOC);
    if (upl || loc) {
      return {
        city: 'Bogotá D.C.',
        scope: 'upl',
        label: upl ? upl.n : null,
        codigo: upl ? upl.k : null,
        sub: loc ? loc.n : null,
        sub_codigo: loc ? loc.k : null,
      };
    }
  }
  // Medellín
  if (lon >= MED_BBOX[0] && lon <= MED_BBOX[2] && lat >= MED_BBOX[1] && lat <= MED_BBOX[3]) {
    const bar = _findInLayer(pt, MED_BAR);
    if (bar) {
      return {
        city: 'Medellín',
        scope: 'barrio',
        label: bar.n,
        codigo: bar.k,
        sub: bar.nombre_com || null,
        sub_codigo: bar.comuna || null,
      };
    }
  }
  // Cali
  if (lon >= CAL_BBOX[0] && lon <= CAL_BBOX[2] && lat >= CAL_BBOX[1] && lat <= CAL_BBOX[3]) {
    const com = _findInLayer(pt, CAL_COM);
    if (com) {
      return {
        city: 'Cali',
        scope: 'comuna',
        label: com.n,
        codigo: com.k,
      };
    }
  }
  return {};
}

// Compat: alias del lookup anterior solo-Bogotá. Devuelve { upl, localidad } como antes.
function bogLookup(lat, lon) {
  const r = cityLookup(lat, lon);
  if (r.city !== 'Bogotá D.C.') return {};
  return {
    upl: r.label ? { nombre: r.label, codigo: r.codigo } : null,
    localidad: r.sub ? { nombre: r.sub, codigo: r.sub_codigo } : null,
  };
}

// ─── Router ───────────────────────────────────────────────────────────────
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    // ─── /geo ─────────────────────────────────────────────────────────────
    // Geolocalización aproximada del cliente (ciudad + lat/lon) desde los
    // headers que Cloudflare añade en `request.cf`. Sin costo.
    // CORS abierto a `*` porque el test se embebe en sitios de terceros
    // (medios) — por eso va ANTES del OPTIONS global, que restringe a
    // ricardoruiz.co. No tocar ese orden.
    if (path === "/geo") {
      if (request.method === "OPTIONS") {
        return new Response(null, {
          status: 204,
          headers: {
            "Access-Control-Allow-Origin":  "*",
            "Access-Control-Allow-Methods": "GET,OPTIONS",
            "Access-Control-Allow-Headers": "content-type",
            "Access-Control-Max-Age":       "86400",
          },
        });
      }
      if (request.method !== "GET") {
        return new Response("Method Not Allowed", { status: 405 });
      }
      const cf = request.cf || {};
      // Permite override via ?lat=X&lon=Y — usado por el test cuando el usuario
      // acepta Geolocation API en el navegador. Si se pasa, sobrescribe lo de cf.*
      // y la respuesta indica overridden:true para que el cliente lo sepa.
      const qLat = url.searchParams.get("lat");
      const qLon = url.searchParams.get("lon");
      let lat = cf.latitude  ? Number(cf.latitude)  : null;
      let lon = cf.longitude ? Number(cf.longitude) : null;
      let overridden = false;
      if (qLat != null && qLon != null) {
        const nl = Number(qLat), no = Number(qLon);
        // Validación: coords razonables (Colombia: lat -5..15, lon -82..-66)
        if (Number.isFinite(nl) && Number.isFinite(no) &&
            nl >= -5 && nl <= 15 && no >= -82 && no <= -66) {
          lat = nl; lon = no; overridden = true;
        }
      }
      const city = cityLookup(lat, lon);
      // Compat: si la ciudad es Bogotá, también exponemos upl/localidad como
      // antes para no romper consumidores que aún usen esos campos.
      const upl       = city.city === "Bogotá D.C." && city.label ? { nombre: city.label, codigo: city.codigo } : null;
      const localidad = city.city === "Bogotá D.C." && city.sub   ? { nombre: city.sub,   codigo: city.sub_codigo } : null;
      const body = {
        city:       cf.city           || null,
        region:     cf.region         || null,
        regionCode: cf.regionCode     || null,
        country:    cf.country        || null,
        lat,
        lon,
        overridden,
        postal:     cf.postalCode     || null,
        timezone:   cf.timezone       || null,
        asn:        cf.asn            || null,
        asOrg:      cf.asOrganization || null,
        // Resolución unificada por ciudad (Bogotá, Medellín, Cali). Si el punto
        // no cae en ninguna, zona queda como null y el frontend usa fallback.
        zona:       city.city ? city : null,  // { city, scope, label, codigo, sub, sub_codigo }
        // Compat con la primera versión que solo devolvía Bogotá:
        upl,
        localidad,
      };
      return new Response(JSON.stringify(body), {
        status: 200,
        headers: {
          "Content-Type":                "application/json; charset=utf-8",
          "Cache-Control":               "no-store",
          "Access-Control-Allow-Origin": "*",
        },
      });
    }

    if (request.method === "OPTIONS") return new Response(null, { status: 204, headers: CORS });

    if (path === "/auth/register"       && request.method === "POST") return register(request, env);
    if (path === "/auth/login"          && request.method === "POST") return login(request, env);
    if (path === "/auth/logout"         && request.method === "POST") return logout(request, env);
    if (path === "/auth/forgot"         && request.method === "POST") return forgot(request, env);
    if (path === "/auth/reset"          && request.method === "POST") return reset(request, env);
    if (path === "/auth/me"             && request.method === "GET")  return me(request, env);
    if (path === "/auth/cancel"         && request.method === "POST") return cancelPlan(request, env);
    if (path === "/auth/magic"          && request.method === "POST") return magicSend(request, env);
    if (path === "/auth/magic/verify"   && request.method === "GET")  return magicVerify(request, env);
    if (path === "/auth/magic/complete" && request.method === "POST") return magicComplete(request, env);
    if (path === "/auth/verify"         && request.method === "GET")  return verifyEmail(request, env);
    if (path === "/wompi/webhook"       && request.method === "POST") return wompiWebhook(request, env);

    return err("Ruta no encontrada", 404);
  }
};

// ─── Auth ─────────────────────────────────────────────────────────────────
async function register(request, env) {
  let body;
  try { body = await request.json(); } catch { return err("JSON inválido"); }
  const { name, email, password, country } = body;
  if (!name || name.trim().length < 2) return err("Nombre inválido");
  if (!email || !email.includes("@")) return err("Email inválido");
  if (!password || password.length < 8) return err("Contraseña muy corta");
  if (!country) return err("País requerido");
  const emailKey = `users:${email.toLowerCase()}`;
  const existing = await env.RR_STORE.get(emailKey);
  if (existing) return err("Ya existe una cuenta con ese correo", 409);
  const salt = randomToken(16);
  const hash = await hashPassword(password, salt);
  const user = { name: name.trim(), email: email.toLowerCase(), country, salt, hash, plan: "free", createdAt: Date.now(), verified: false };
  await env.RR_STORE.put(emailKey, JSON.stringify(user));
  const token = randomToken();
  await env.RR_STORE.put(`sessions:${token}`, JSON.stringify({ email: email.toLowerCase(), name: user.name, plan: user.plan, createdAt: Date.now() }), { expirationTtl: 60 * 60 * 24 * 30 });

  // ── Enviar email de verificación ─────────────────────────────────────────
  const verifyToken = randomToken(24);
  await env.RR_STORE.put(
    `verify:${verifyToken}`,
    JSON.stringify({ email: email.toLowerCase(), createdAt: Date.now() }),
    { expirationTtl: 60 * 60 * 48 } // 48 horas
  );
  const verifyUrl = `https://rr-auth.reruizc.workers.dev/auth/verify?token=${verifyToken}`;
  try {
    await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: { "Authorization": `Bearer ${env.RESEND_API_KEY}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        from: "Ricardo Ruiz <noreply@ricardoruiz.co>",
        to: email,
        reply_to: "reruizc@gmail.com",
        subject: "Confirma tu cuenta · ricardoruiz.co",
        html: `<!DOCTYPE html><html><head><meta charset="UTF-8"/></head><body style="background:#0a0a0a;color:#f4f3ef;font-family:'Courier New',monospace;padding:40px 20px;margin:0;"><div style="max-width:480px;margin:0 auto;"><div style="margin-bottom:32px;"><span style="font-family:sans-serif;font-weight:800;font-size:18px;letter-spacing:-0.02em;">Ricardo<span style="color:#0047FF;">.</span>Ruiz</span></div><div style="border-left:3px solid #0047FF;padding-left:20px;margin-bottom:32px;"><p style="font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#0047FF;margin:0 0 8px;">Verificación de cuenta</p><h1 style="font-family:sans-serif;font-weight:800;font-size:28px;letter-spacing:-0.03em;margin:0;line-height:1;">Confirma tu email</h1></div><p style="font-size:14px;line-height:1.7;color:#888;margin-bottom:32px;">Hola ${user.name.trim().split(" ")[0]}, haz clic para activar tu cuenta. Este enlace expira en <strong style="color:#f4f3ef;">48 horas</strong>.</p><a href="${verifyUrl}" style="display:block;background:#0047FF;color:#fff;text-align:center;padding:16px 32px;text-decoration:none;font-family:'Courier New',monospace;font-size:13px;letter-spacing:0.1em;text-transform:uppercase;margin-bottom:32px;">Verificar mi cuenta →</a><p style="font-size:11px;color:#333;line-height:1.6;">Si no creaste esta cuenta, ignora este mensaje.</p><p style="font-size:11px;color:#222;margin-top:8px;word-break:break-all;">O copia: ${verifyUrl}</p><div style="margin-top:40px;padding-top:20px;border-top:1px solid #1a1a1a;"><p style="font-size:10px;letter-spacing:0.1em;color:#333;text-transform:uppercase;">ricardoruiz.co · Bogotá, Colombia</p></div></div></body></html>`
      })
    });
  } catch (e) { console.error("Verify email send failed:", e.message); }

  return ok({ message: "Cuenta creada", token, user: { name: user.name, email: user.email, plan: user.plan } });
}

async function login(request, env) {
  let body;
  try { body = await request.json(); } catch { return err("JSON inválido"); }
  const { email, password } = body;
  if (!email || !password) return err("Email y contraseña requeridos");
  const raw = await env.RR_STORE.get(`users:${email.toLowerCase()}`);
  if (!raw) return err("Credenciales incorrectas", 401);
  const user = JSON.parse(raw);
  const hash = await hashPassword(password, user.salt);
  if (hash !== user.hash) return err("Credenciales incorrectas", 401);
  const token = randomToken();
  await env.RR_STORE.put(`sessions:${token}`, JSON.stringify({ email: user.email, name: user.name, plan: user.plan, createdAt: Date.now() }), { expirationTtl: 60 * 60 * 24 * 30 });
  return ok({ message: "Sesión iniciada", token, user: { name: user.name, email: user.email, plan: user.plan } });
}

async function logout(request, env) {
  const token = getToken(request);
  if (token) await env.RR_STORE.delete(`sessions:${token}`);
  return ok({ message: "Sesión cerrada" });
}

// ─── Me: lee el plan en VIVO desde el usuario (no desde la sesión) ────────
async function me(request, env) {
  const token = getToken(request);
  if (!token) return err("No autenticado", 401);
  const raw = await env.RR_STORE.get(`sessions:${token}`);
  if (!raw) return err("Sesión expirada o inválida", 401);
  const session = JSON.parse(raw);
  const userRaw = await env.RR_STORE.get(`users:${session.email}`);
  if (!userRaw) return ok({ user: { name: session.name, email: session.email, plan: session.plan } });

  const user = JSON.parse(userRaw);

  // Downgrade automático si el plan venció
  if (user.plan !== "free" && user.planExpiresAt && Date.now() > user.planExpiresAt) {
    user.plan = "free";
    user.planExpiresAt = null;
    user.billingCycle = null;
    await env.RR_STORE.put(`users:${session.email}`, JSON.stringify(user));
  }

  return ok({ user: {
    name: user.name,
    email: user.email,
    plan: user.plan,
    planExpiresAt: user.planExpiresAt || null,
    billingCycle: user.billingCycle || null,
    cancelledAt: user.cancelledAt || null,
  }});
}

// ─── Cancel: marca el plan como cancelado (sigue activo hasta planExpiresAt) ──
async function cancelPlan(request, env) {
  const token = getToken(request);
  if (!token) return err("No autenticado", 401);
  const raw = await env.RR_STORE.get(`sessions:${token}`);
  if (!raw) return err("Sesión expirada o inválida", 401);
  const session = JSON.parse(raw);

  const userRaw = await env.RR_STORE.get(`users:${session.email}`);
  if (!userRaw) return err("Usuario no encontrado", 404);
  const user = JSON.parse(userRaw);

  if (user.plan === "free") return err("No tienes un plan activo para cancelar", 400);
  if (user.cancelledAt) return err("El plan ya está cancelado", 400);

  user.cancelledAt = Date.now();
  await env.RR_STORE.put(`users:${session.email}`, JSON.stringify(user));

  return ok({
    message: "Plan cancelado. Tu acceso continúa hasta la fecha de expiración.",
    planExpiresAt: user.planExpiresAt,
  });
}

// ─── Verificación de email ────────────────────────────────────────────────
async function verifyEmail(request, env) {
  const url   = new URL(request.url);
  const token = url.searchParams.get("token");
  if (!token) return Response.redirect("https://ricardoruiz.co/login.html?error=invalid", 302);
  const raw = await env.RR_STORE.get(`verify:${token}`);
  if (!raw) return Response.redirect("https://ricardoruiz.co/login.html?error=expired", 302);
  const { email } = JSON.parse(raw);
  await env.RR_STORE.delete(`verify:${token}`);
  const userRaw = await env.RR_STORE.get(`users:${email}`);
  if (!userRaw) return Response.redirect("https://ricardoruiz.co/login.html?error=notfound", 302);
  const user = JSON.parse(userRaw);
  user.verified = true;
  await env.RR_STORE.put(`users:${email}`, JSON.stringify(user));
  return Response.redirect("https://ricardoruiz.co/dashboard.html?verified=1", 302);
}

// ─── Webhook de Wompi ─────────────────────────────────────────────────────
async function wompiWebhook(request, env) {
  let body;
  try { body = await request.json(); } catch {
    return new Response("Bad Request", { status: 400 });
  }

  const { signature, data, timestamp, event } = body;
  if (!signature?.properties || !signature?.checksum || !timestamp) {
    return new Response("Invalid payload", { status: 400 });
  }

  // Verificar firma: SHA256(prop1val + prop2val + ... + timestamp + WOMPI_EVENTS_KEY)
  let toHash = "";
  for (const prop of signature.properties) {
    const parts = prop.split(".");
    let val = body;
    for (const p of parts) val = val?.[p];
    toHash += String(val ?? "");
  }
  toHash += timestamp;
  toHash += env.WOMPI_EVENTS_KEY;

  const enc = new TextEncoder();
  const hashBuf = await crypto.subtle.digest("SHA-256", enc.encode(toHash));
  const hashHex = Array.from(new Uint8Array(hashBuf)).map(b => b.toString(16).padStart(2, "0")).join("");

  if (hashHex !== signature.checksum) {
    console.error(`[wompi] firma inválida — checksum recibido: ${signature.checksum}`);
    return new Response("Unauthorized", { status: 401 });
  }

  console.log(`[wompi] event=${event} status=${data?.transaction?.status} email=${data?.transaction?.customer_email} linkId=${data?.transaction?.payment_link_id} txId=${data?.transaction?.id}`);

  // Procesar pago aprobado
  if (event === "transaction.updated") {
    const tx = data?.transaction;
    if (tx?.status === "APPROVED") {
      const linkId = tx.payment_link_id;
      const entry = LINK_PLAN_MAP[linkId];

      if (!entry) {
        console.error(`[wompi] SKIP: linkId "${linkId}" no está en LINK_PLAN_MAP — tx ${tx.id}`);
      } else {
        // Identificar usuario: primero por customer_email, luego por email en reference
        // reference tiene formato: rr-EMAIL-planId-billing-timestamp
        const emailFromCheckout = tx.customer_email?.toLowerCase();
        let email = emailFromCheckout;
        let userRaw = email ? await env.RR_STORE.get(`users:${email}`) : null;

        if (!userRaw && tx.reference) {
          const refMatch = tx.reference.match(/^rr-(.+?)-(?:pro|premium)_/);
          if (refMatch) {
            const refEmail = refMatch[1].toLowerCase();
            if (refEmail.includes("@")) {
              console.log(`[wompi] email extraído de reference: ${refEmail} — tx ${tx.id}`);
              email = refEmail;
              userRaw = await env.RR_STORE.get(`users:${email}`);
            }
          }
        }

        if (!email) {
          console.error(`[wompi] SKIP: sin customer_email ni reference válido — tx ${tx.id}`);
        } else if (!userRaw) {
          console.error(`[wompi] SKIP: usuario "${email}" no existe en KV — tx ${tx.id}`);
        } else {
          const user = JSON.parse(userRaw);
          const now = Date.now();
          user.plan = entry.plan;
          user.planUpdatedAt = now;
          user.planLinkId = linkId;
          user.billingCycle = entry.cycle;
          user.planExpiresAt = now + CYCLE_DAYS[entry.cycle] * 24 * 60 * 60 * 1000;
          delete user.cancelledAt; // una renovación reactiva el plan
          await env.RR_STORE.put(`users:${email}`, JSON.stringify(user));
          console.log(`[wompi] OK: ${email} → plan=${entry.plan} cycle=${entry.cycle} tx=${tx.id}`);
        }
      }
    }
  }

  return new Response(JSON.stringify({ received: true }), {
    status: 200,
    headers: { "Content-Type": "application/json" }
  });
}

// ─── Recuperación de contraseña ───────────────────────────────────────────
async function forgot(request, env) {
  let body;
  try { body = await request.json(); } catch { return err("JSON inválido"); }
  const { email } = body;
  if (!email) return err("Email requerido");
  const raw = await env.RR_STORE.get(`users:${email.toLowerCase()}`);
  if (!raw) return ok({ message: "Si el correo existe, recibirás un código" });
  const user = JSON.parse(raw);
  const code = randomCode();
  await env.RR_STORE.put(`reset:${email.toLowerCase()}`, JSON.stringify({ code, createdAt: Date.now() }), { expirationTtl: 60 * 15 });
  try {
    await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: { "Authorization": `Bearer ${env.RESEND_API_KEY}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        from: "Ricardo Ruiz <noreply@ricardoruiz.co>",
        to: email,
        reply_to: "reruizc@gmail.com",
        subject: `Tu código de verificación: ${code}`,
        html: `<!DOCTYPE html><html><head><meta charset="UTF-8"/></head><body style="background:#0a0a0a;color:#f4f3ef;font-family:'Courier New',monospace;padding:40px 20px;margin:0;"><div style="max-width:480px;margin:0 auto;"><div style="margin-bottom:32px;"><span style="font-family:sans-serif;font-weight:800;font-size:18px;letter-spacing:-0.02em;">Ricardo<span style="color:#0047FF;">.</span>Ruiz</span></div><div style="border-left:3px solid #0047FF;padding-left:20px;margin-bottom:32px;"><p style="font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#0047FF;margin:0 0 8px;">Recuperación de contraseña</p><h1 style="font-family:sans-serif;font-weight:800;font-size:28px;letter-spacing:-0.03em;margin:0;line-height:1;">Tu código</h1></div><p style="font-size:14px;line-height:1.7;color:#888;margin-bottom:32px;">Hola ${user.name.split(" ")[0]}, usa el siguiente código para restablecer tu contraseña. Expira en <strong style="color:#f4f3ef;">15 minutos</strong>.</p><div style="background:#111;border:1px solid #1e1e1e;padding:24px;text-align:center;margin-bottom:32px;"><span style="font-family:'Courier New',monospace;font-size:36px;font-weight:700;letter-spacing:0.3em;color:#0047FF;">${code}</span></div><p style="font-size:11px;color:#333;line-height:1.6;">Si no solicitaste este código, ignora este mensaje.</p><div style="margin-top:40px;padding-top:20px;border-top:1px solid #1a1a1a;"><p style="font-size:10px;letter-spacing:0.1em;color:#333;text-transform:uppercase;">ricardoruiz.co · Bogotá, Colombia</p></div></div></body></html>`
      })
    });
  } catch (e) { console.error("Email send failed:", e.message); }
  return ok({ message: "Si el correo existe, recibirás un código" });
}

async function reset(request, env) {
  let body;
  try { body = await request.json(); } catch { return err("JSON inválido"); }
  const { email, code, password } = body;
  if (!email || !code || !password) return err("Faltan campos");
  if (password.length < 8) return err("Contraseña muy corta");
  const raw = await env.RR_STORE.get(`reset:${email.toLowerCase()}`);
  if (!raw) return err("Código expirado o inválido", 400);
  const { code: savedCode } = JSON.parse(raw);
  if (code !== savedCode) return err("Código incorrecto", 400);
  const userRaw = await env.RR_STORE.get(`users:${email.toLowerCase()}`);
  if (!userRaw) return err("Usuario no encontrado", 404);
  const user = JSON.parse(userRaw);
  const salt = randomToken(16);
  const hash = await hashPassword(password, salt);
  user.salt = salt;
  user.hash = hash;
  await env.RR_STORE.put(`users:${email.toLowerCase()}`, JSON.stringify(user));
  await env.RR_STORE.delete(`reset:${email.toLowerCase()}`);
  return ok({ message: "Contraseña actualizada" });
}

